{
  "name": "Healthy Connections Medicaid",
  "eligibility": {
    "age": 65,
    "income_limits": "For elderly (65+): Income under $2,982/month for single nursing home applicants in 2026. General Medicaid: Varies by category—parents/caretakers up to 100% FPL, children up to 213% FPL, pregnant women up to 199% FPL. Exact dollar amounts depend on current FPL and household size; no full table in sources but includes 5% disregard. For long-term care, requires Nursing Facility Level of Care (NFLOC).[2][6]",
    "asset_limits": "For elderly long-term care (e.g., nursing home): $2,000 for single applicants. Counts checking/savings accounts and other resources; exemptions not detailed but typical Medicaid rules apply (e.g., primary home often exempt). Eligibility based on income and assets.[3][6]",
    "other_requirements": ["Blind or totally/permanently disabled", "Nursing home level of care for long-term services", "Functional need for ADLs in regular program", "U.S. citizen or qualified immigrant", "South Carolina resident"]
  },
  "benefits": {
    "type": "service",
    "value": "Pays for medical bills, nursing facility care, other medical expenses for eligible elderly/disabled. Covers doctor visits, hospital care, prescriptions via managed care plans. Specific long-term care requires NFLOC; no fixed dollar/hour amounts listed.[1][3][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://apply.scdhhs.gov or https://www.scdhhs.gov/how-to-apply", "Phone: 1-888-549-0820 (TTY: 888-842-3620)", "Mail: Request paper application by calling 888-549-0820", "In-person: Local county office or authorized hospitals/Family Health Centers (e.g., call 803-531-6900)"],
    "processing_time": "Up to 45 days; longer for certain categories like disability.[7]",
    "waitlist": null,
    "forms": ["Online application at apply.scdhhs.gov; no specific form number listed"],
    "documents": ["Date of birth", "Social Security Number", "Income from jobs/training", "Benefits (SSI, Social Security, veterans, child support)", "Bank account balances/resources", "Rent/mortgage/utility bills", "Health coverage/medical payments for household members.[3][4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "South Carolina residents only",
    "regional_variations": "Processing times may vary; apply at local county offices. No major benefit differences noted.[7]",
    "offices_or_providers": ["Local county offices", "Family Health Centers (e.g., 803-531-6900)"]
  },
  "official_source": "https://www.scdhhs.gov",
  "gotchas": ["Must enroll in managed care plan (90-day switch window, then limited changes).[5]", "SC did not expand Medicaid under ACA, so limited parental coverage.[2]", "Apply directly to SCDHHS, not Marketplace for final determination if assessed eligible there.[7]", "Hospitals cannot delegate eligibility determinations.[7]", "Long-term care needs NFLOC; income/assets strictly for nursing home programs.[6]"],
  "data_shape_notes": "Elderly focus on long-term care with strict $2,982 income/$2,000 asset for singles; managed care mandatory post-eligibility; no statewide waitlist info; varies by care need (NFLOC/ADL)"
}

{
  "name": "South Carolina PACE",
  "eligibility": {
    "age": 55,
    "income_limits": "No specific income limits; participants must have Medicare or Medicaid (or both). For Medicaid long-term care eligibility, income generally under $2,901/month (300% of Federal Benefit Rate in 2025), but varies by state rules and not a direct PACE barrier.[1][4]",
    "asset_limits": "No asset limits for PACE enrollment itself. Medicaid may require assets $2,000 or less (excluding primary home) for dual eligibles.[4]",
    "other_requirements": [
      "Live in the service area of a PACE organization.",
      "Meet nursing home-level of care as certified by South Carolina Department of Health and Human Services.",
      "Be able to live safely in the community with PACE help.",
      "Have Medicare or Medicaid (or both); cannot be in Medicare Advantage, hospice, or certain other programs."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "All-inclusive care for the elderly including primary care, hospital care, prescription drugs, social services, restorative therapies, home care, respite care, and all other needed services to maintain community living; no specific dollar amounts or hours stated, comprehensive coverage via PACE organization.[1][2]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Contact SCDHHS or PACE organization in service area (specific phone/website via https://www.scdhhs.gov/members/managed-care-plan-information/program-all-inclusive-care-elderly-pace/members)",
      "No specific forms, phone numbers, or addresses listed in sources; start via SCDHHS site or local PACE provider."
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not specified; may exist due to limited service areas.",
    "forms": [],
    "documents": [
      "Proof of age, residency in service area, Medicare/Medicaid status, documentation for nursing home-level care assessment."
    ]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Only available in certain counties/service areas of PACE organizations in South Carolina.[1]",
    "regional_variations": "Limited to specific PACE organization service areas; different providers by region, potential waitlist or availability differences.",
    "offices_or_providers": ["Service areas noted on SCDHHS site; specific counties not listed in results."]
  },
  "official_source": "https://www.scdhhs.gov/members/managed-care-plan-information/program-all-inclusive-care-elderly-pace/members",
  "gotchas": [
    "Not statewide—must live in a PACE service area; check specific counties.",
    "Requires nursing home-level care certification, but must be able to live safely in community (not for those needing full nursing home).",
    "No financial eligibility barrier for enrollment, but most need Medicaid/Medicare; cannot be in Medicare Advantage or hospice.",
    "Voluntary enrollment; average participant is 76 with complex needs."
  ],
  "data_shape_notes": "Limited to specific counties/service areas with PACE organizations; no income/asset test for enrollment itself, but tied to Medicare/Medicaid and nursing home-level care; not statewide."
}

{
  "name": "SNAP (Food Assistance)",
  "eligibility": {
    "age": 60,
    "income_limits": "For households with elderly (60+) or disabled members (Oct 1, 2025 - Sept 30, 2026): Standard gross income limit at 130% FPL - 1: $1695/mo, 2: $2291, 3: $2887, 4: $3482, 5: $4079, 6: $4674, 7: $5270, +$595 each additional. Expanded for households where all adults are 60+ or disabled: 1: $2608/mo, 2: $3526, 3: $4442, 4: $5358, 5: $6276, 6: $7192, 7: $8108, +$916 each additional (165% FPL). Elderly/disabled households tested on net income at 100% FPL; may qualify under federal rules with $4500 assets if gross test not met. ESAP specific: 60+, no earned income, not on SCCAP.[1][2][3]",
    "asset_limits": "Generally no asset limit for elderly/disabled households in SC (expanded eligibility). Federal fallback: $4500 limit if gross income test not met (counts bank accounts; excludes primary home, most vehicles, etc.). Application may still request assets.[2]",
    "other_requirements": ["No earned income for ESAP households.", "Not receiving SNAP via SCCAP.", "U.S. citizen or qualified non-citizen.", "Live in SC.", "Meet net income test for elderly/disabled.", "Deductions apply: medical >$35 for 60+, shelter, utilities, etc."][1][2][3][5]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card for food purchases. Amount based on net income, household size, deductions (e.g., example 2-person elderly: $415/mo after calc). Exact varies; max allotment minus 30% net income.[2][6]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Mail DSS ESAP Application to ESAP, South Carolina Department of Social Services, PO Box 100203, Columbia, SC 29202 (download from dss.sc.gov).", "Call 1-888-898-0055 for ESAP/SCCAP info.", "Standard SNAP: Online via dss.sc.gov, local DSS offices, or mail."],
    "processing_time": "Notified in writing of decision; benefits from application file date if eligible. ESAP certification up to 36 months, no recert interview.[1][5]",
    "waitlist": null,
    "forms": ["DSS ESAP Application"],
    "documents": ["Proof of age/income (Social Security, pension statements), expenses (medical, shelter, utilities), identity, residency. ESAP uses data matches to reduce verification needs."][1][2][3]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": ["Local DSS county offices for standard SNAP; ESAP mailed statewide to Columbia PO Box."]
  },
  "official_source": "https://dss.sc.gov/assistance-programs/snap/",
  "gotchas": ["ESAP requires no earned income and not on SCCAP - check first.", "Even if assets exempt, application may ask for them.", "Social Security/pensions count as income.", "ESAP vs SCCAP: SCCAP for SSI recipients.", "New 2025 federal work rules may apply if able-bodied (not typical for elderly).", "Only gross test if assets >$4500 under federal fallback."[1][2][3][5][6][8]],
  "data_shape_notes": "Elderly-specific ESAP simplifies process (no earned income, 36-mo cert, data matches); expanded income limits/asset waivers for 60+/disabled; benefits calculated via net income table with deductions scaling by household size and expenses."
}

{
  "name": "LIHEAP (Home Energy Assistance)",
  "eligibility": {
    "age": null,
    "income_limits": "Varies by provider and guidelines used (e.g., 60% State Median Income (SMI), 150% Federal Poverty Level (FPL), or Federal Poverty Guidelines). Exact limits differ; examples: From [2] (monthly gross income): 1: $2,666; 2: $3,486; 3: $4,306; 4: $5,127; 5: $5,947; 6: $6,767. From [3] (60% SMI monthly): 1: $2,332.83; 2: $3,050.58; 3: $3,768.42; 4: $4,486.25; 5: $5,204; 6: $5,921.83; 7: $6,056.42; 8: $6,191. Households assessed individually; priority for elderly, disabled, children ≤5, or high energy burden.",
    "asset_limits": "No asset limit statewide.[2]",
    "other_requirements": ["SC resident in service area of local Community Action Agency (county-specific).", "Proof of income for past 30 days for all household members.", "SC-issued picture ID with current address.", "Social Security cards for all household members.", "Energy bill in household member's name.", "Citizenship status verification.", "Priority for vulnerable households (elderly, disabled, young children, emergencies)."]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payments to utility providers for heating/cooling bills. Max: Heating $850, Cooling $775, Crisis $1,500 (up to $1,500 per service, max 2 services/year).[2][4] Min: $200 (heating/cooling). Covers electricity, natural gas, propane, fuel oil, kerosene, wood/coal; cooling may include window AC/fans.[7] Crisis for shutoffs/emergencies; separate weatherization possible.",
    "varies_by": "priority_tier|region|household_size"
  },
  "application": {
    "methods": ["Contact local Community Action Agency by county (see map at oeo.sc.gov).[4][5]", "Phone: Governor’s Office of Economic Opportunity 803-734-0662 for info/direction.[4]", "Online: Provider-specific (e.g., carolinacommunityactions.org/apply-here, palmettocap.org).[1][3]", "In-person/mail: Local agency offices (e.g., GLEAMNS: 237 N Hospital St, Greenwood, SC).[5][6]"],
    "processing_time": "Not specified; intake interview scheduled after contact.",
    "waitlist": "Funds limited; available until exhausted. Seasonal: Heating Oct-winter, Cooling May-Sep, Crisis year-round emergencies.[2]",
    "forms": ["Agency-specific intake forms; no universal state form number."],
    "documents": ["SC photo ID with address.", "SS cards for all household members.", "Proof of all household income (past 30 days).", "Recent energy bills.", "Rental agreement if applicable.", "Tax records.", "Proof of citizenship/SSN."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered county-by-county via local Community Action Agencies; must apply through agency serving your county.",
    "regional_variations": "Yes: Different providers (e.g., Palmetto CAP: Berkeley/Charleston/Dorchester[1]; Carolina Community Actions: uses 60% SMI[3]; GLEAMNS: specific counties like Greenwood/Laurens[6]; SHARES: up to 150% FPL, seasonal[7]). Income guidelines, max benefits, service areas vary.",
    "offices_or_providers": ["Local Community Action Agencies (full map: oeo.sc.gov).[4][5]"]
  },
  "official_source": "https://oeo.sc.gov/managedsites/prd/oeo/liheap.html",
  "gotchas": ["Not statewide uniform—must use exact county agency; income calculated uniquely (past 30 days, full household incl. roommates on bill).[1][2]", "Funds exhaust quickly; seasonal availability.[2][7]", "Priority for elderly/vulnerable/emergencies—others may miss out.[3][6]", "Renter with included utilities needs itemized bill.[4]", "Max 2 services/year.[4]"],
  "data_shape_notes": "County-administered via local agencies with varying income guidelines (60% SMI, FPL), providers, and limits; priority-tiered for vulnerable (elderly prioritized); funds limited/seasonal; no asset test."
}

{
  "name": "Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Not means-tested; no income or asset disclosure required for denial of services. Prioritizes those with Greatest Economic Need (income at or below poverty line, generally 125%-200% of federal poverty guidelines in SC) and Greatest Social Need (non-economic factors like disabilities, isolation, language barriers). For referrals to SC Legal Services, income typically ≤125% FPL (exceptions to 200% FPL) with assets ≤$3,000 per person (exclusions apply).[1][3][4]",
    "asset_limits": "No asset limits or tests for the core Legal Assistance Services Program. SC Legal Services (referral option) has $3,000 per person limit (liquid/non-liquid) with certain exclusions.[1][3]",
    "other_requirements": ["Greatest Economic Need or Greatest Social Need prioritized due to limited resources.", "South Carolina resident.", "Civil legal matters only (non-criminal)."]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal assistance and elder rights services under Older Americans Act (OAA), including representation, advice, and advocacy to maximize independence and well-being. Specific areas: elder rights, autonomy protection. Referrals to SC Legal Services or SC Bar if not prioritized.[1]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) or Council on Aging (COG), e.g., Santee Lynches COG form: https://www.santeelynchescog.org/sites/default/files/uploads/aging/legalservicesform.pdf (mail/submit).", "SC Legal Services (referral): Online intake at sclegal.org; phone 1-888-346-5592 or regional (e.g., Charleston: 843-720-7044, toll-free 888-720-2320).", "SC Bar Lawyer Referral: (803) 799-7100 or online.", "In-person/walk-in/phone at local offices with proof of residence/income/ID/legal docs.[3][5]"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Possible due to limited OAA resources; prioritization affects access.[1]",
    "forms": ["Legal Services Program form (e.g., Santee Lynches COG PDF).", "SC Legal Services online intake form.", "SCDHHS Healthy Connections Application (if related Medicaid, but not core).[1][2]"],
    "documents": ["Proof of age (ID), residence, income/benefits (for resource identification, not denial), legal documents if applicable. No mandatory income/asset disclosure for program.[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via 10 SC Area Agencies on Aging/Councils on Aging; prioritizes targeted populations.",
    "regional_variations": "Administered by local AAAs/COGs (e.g., Santee Lynches COG); different offices/providers by region. SC Legal Services has regional offices (e.g., Charleston). Wait times/resources may vary.[1][3]",
    "offices_or_providers": ["Local Councils on Aging/Area Agencies on Aging (10 statewide).", "SC Legal Services regional offices.", "SC Bar statewide referral."]
  },
  "official_source": "https://www.santeelynchescog.org/sites/default/files/uploads/aging/legalservicesform.pdf (example AAA); sclegal.org (referral partner)",
  "gotchas": ["Not means-tested but heavily prioritized for greatest economic/social need—higher income seniors may get referrals only, not direct services.[1]", "Limited OAA funding means not all seniors served; expect referrals to means-tested SC Legal Services (125% FPL, $3k assets).[1][3][4]", "Focus on elder rights/OAA-specific issues; not general legal aid.", "No criminal matters; prisoners excluded from some providers.[3]", "Income questions asked for resource targeting, despite no denial based on them.[1]"],
  "data_shape_notes": "No income/asset test but priority-based on need tiers; delivered via 10 regional AAAs/COGs; referrals to means-tested alternatives scale by household FPL and assets."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Resident must be in a long-term care facility (nursing homes, assisted living, community residential care facilities, DDSN or DMH facilities) in South Carolina.", "Complaint must relate to quality of care, quality of life, rights violations, improper transfer/discharge, benefits assistance, dignity/respect, or abuse/neglect/exploitation.", "Available to residents, family, friends, facility staff, or any concerned community member filing on behalf of a resident."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigates and resolves complaints; advocates for resident rights; assists with appeals/grievances; provides education on resident rights/benefits; offers information/referrals for long-term care services; mediates between residents/families and facilities; promotes community involvement; no cost for services; no fixed dollar amounts or hours—support provided as needed per complaint.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide toll-free 1-800-868-9095 (for abuse/neglect suspicions or general complaints)[1]", "Phone: State office 803-734-9900[1][5]", "Regional offices (examples: Santee-Lynches at 803-774-1983 or sbrooks@slcog.org[2]; Appalachian COG at 864-242-9733 or ombudintake@scacog.org[3])", "In-person or walk-in at regional offices", "Email to regional coordinators", "No specific online application form; contact to file complaint"],
    "processing_time": "Not specified; ombudsman investigates promptly upon contact, determines validity, mediates resolution, and follows up—no formal processing timeline stated.",
    "waitlist": null,
    "forms": ["No specific forms required; complaints filed via phone, email, or in-person—no form name/number mentioned."],
    "documents": ["No documents needed to file; provide details of the complaint (e.g., facility name, resident info, issue description). Confidentiality protected unless permission given."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in South Carolina long-term care facilities (2,039 facilities with 43,678 beds).",
    "regional_variations": "Administered statewide by SC Department on Aging through 10 regional offices (e.g., Santee-Lynches covers Clarendon, Lee, Kershaw, Sumter counties[2]; Appalachian COG covers Anderson, Cherokee, Greenville, Oconee, Pickens, Spartanburg[3]); contact regional office for local intake, but services consistent statewide.",
    "offices_or_providers": ["10 regional offices via SC Department on Aging; state office at 1301 Gervais Street, Suite 350, Columbia, SC 29201[5]"]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/long-term-care-ombudsman-program[1]",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy for complaints in facilities; does not provide direct services like care or payments.", "Only for long-term care facility residents—not community-dwelling adults (separate reporting for community abuse).", "Complaints handled confidentially, but identity may need disclosure for resolution (resident chooses).", "Anyone can file, not just family or residents.", "Volunteers also provide visits/encouragement, but core service is complaint resolution."],
  "data_shape_notes": "no income test; free advocacy service only for LTC facility residents statewide via 10 regional offices; complaint-driven, not enrollment-based; not a qualification/application program but open-access support."
}

{
  "name": "Senior Farmers Market Nutrition Program",
  "eligibility": {
    "age": 60,
    "income_limits": "Total household gross income cannot exceed 185% of the federal poverty income limits. Specific dollar amounts not listed in sources; applicants self-declare annual gross income and household size. Visit DSS.SC.gov for current table by household size[1][2][4].",
    "asset_limits": null,
    "other_requirements": ["Reside in South Carolina", "Apply in person at approved local senior-serving organizations or distribution events in county of residence (some counties like Moncks Corner allow online)", "Must reapply each year", "Proof of identity required (valid SC driver's license or state-issued ID)"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "$50 in checks/vouchers usable for fresh, unprocessed fruits, vegetables, honey, and herbs at authorized local farmers’ markets, roadside stands, and community-supported agriculture programs. Program runs May 1 to October 15 (checks redeemable through November 15 in 2024; 2026 dates TBD)[1][2][3][5].",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["In-person at approved local senior-serving organizations or distribution events in county of residence (statewide requirement per DSS)", "Online in some counties (e.g., Moncks Corner: specific link not provided in results)", "Phone for info: DSS Coordinator Willie Nixon at 803-898-1760; SCDA Coordinator Anne Nidiffer at 803-734-0347[2][5]", "Website: DSS.SC.gov for eligibility details and events"],
    "processing_time": "Eligibility determination via email (for online) or at event; issued first-come, first-served until funds exhausted[1][2].",
    "waitlist": "Possible referral to waiting list if funds low[1][2].",
    "forms": ["Application completed in-person or online; self-declare income/household size; no specific form name/number listed"],
    "documents": ["Proof of identity (valid SC driver's license or state-issued ID, required to apply and pick up)", "Self-declaration of annual gross income and household size"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Available in 42 counties (evolved from 6-county pilot); must apply in county of residence (e.g., Lancaster-specific events)[2][3].",
    "regional_variations": "Distribution events and application sites vary by county (e.g., in-person only at local organizations; some like Moncks Corner offer online); first-come first-served may lead to regional waitlist differences; find voucher sites via county links[1][2][3].",
    "offices_or_providers": ["Local senior-serving organizations and events by county", "SC DSS: 1535 Confederate Avenue, Columbia, SC 29201", "SCDA: P.O. Box 11280, Columbia, SC 29211"]
  },
  "official_source": "https://dss.sc.gov/ (via DSS.SC.gov) and https://agriculture.sc.gov/divisions/agency-operations/grants/sfmnp/[1][5]",
  "gotchas": ["Program is seasonal and currently ended; returns in 2026—do not apply now[1]", "In-person application required statewide at county events (exceptions rare like Moncks Corner online)[1][3]", "First-come, first-served until funds gone—early application critical[2]", "Must be 60+ on application date; reapply yearly[1][2]", "Only unprocessed local produce; check authorized markets[1][3]"],
  "data_shape_notes": "County-restricted to 42/46 counties with local in-person events; fixed $50 benefit; no asset test or detailed income table in sources (self-declared at 185% FPL); administered by SC DSS with SCDA partnership"
}
